@namespace Lumeo

<span class="@ContainerClass" @attributes="AdditionalAttributes">
    @foreach (var segment in _segments)
    {
        if (segment.IsMatch)
        {
            @RenderMatch(segment.Text)
        }
        else
        {
            @segment.Text
        }
    }
</span>

@code {
    [Parameter] public string Text { get; set; } = "";
    [Parameter] public string? Highlight { get; set; }
    [Parameter] public IEnumerable<string>? HighlightTerms { get; set; }
    [Parameter] public bool CaseSensitive { get; set; }
    [Parameter] public bool WholeWord { get; set; }
    /// <summary>
    /// Treat <see cref="Highlight"/> / <see cref="HighlightTerms"/> as regular-
    /// expression patterns instead of literal text (the default). Invalid
    /// patterns fall back to rendering the text un-highlighted. <see cref="WholeWord"/>
    /// is ignored in this mode — express boundaries in the pattern itself. (#293)
    /// </summary>
    [Parameter] public bool RegexMode { get; set; }
    [Parameter] public string? HighlightClass { get; set; }
    [Parameter] public string Tag { get; set; } = "mark";
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private List<Segment> _segments = new();

    private string ContainerClass => Cx.Merge(Class);

    private string MarkClass =>
        ($"bg-warning/30 text-foreground rounded-sm px-0.5 {HighlightClass}").Trim();

    // Render the highlight wrapper with the consumer-configured element name
    // (Tag parameter, default "mark") instead of a hardcoded <mark>.
    private RenderFragment RenderMatch(string text) => builder =>
    {
        builder.OpenElement(0, string.IsNullOrWhiteSpace(Tag) ? "mark" : Tag);
        builder.AddAttribute(1, "class", MarkClass);
        builder.AddContent(2, text);
        builder.CloseElement();
    };

    protected override void OnParametersSet() => Rebuild();

    private void Rebuild()
    {
        _segments.Clear();

        if (string.IsNullOrEmpty(Text))
            return;

        // Collect terms, largest first to ensure longest match wins
        var terms = new List<string>();
        if (!string.IsNullOrEmpty(Highlight))
            terms.Add(Highlight);
        if (HighlightTerms is not null)
            terms.AddRange(HighlightTerms.Where(t => !string.IsNullOrEmpty(t)));

        // De-duplicate
        terms = terms.Distinct(
            CaseSensitive ? StringComparer.Ordinal : StringComparer.OrdinalIgnoreCase
        ).OrderByDescending(t => t.Length).ToList();

        if (terms.Count == 0)
        {
            _segments.Add(new Segment(Text, false));
            return;
        }

        // Build a combined regex: alternate longest-first
        var escaped = terms.Select(t =>
        {
            // RegexMode: use the term verbatim as a pattern. Otherwise escape it
            // to a literal and optionally anchor on word boundaries.
            if (RegexMode) return t;
            var e = System.Text.RegularExpressions.Regex.Escape(t);
            if (!WholeWord)
                return e;
            // Only anchor a \b on a side whose adjacent term char is itself a word
            // character. A \b next to punctuation (e.g. "C#", ".NET", "(World)")
            // can never match, which would silently drop the term. (t is already
            // guaranteed non-empty by the collection filters above.)
            var left = char.IsLetterOrDigit(t[0]) || t[0] == '_' ? @"\b" : "";
            var right = char.IsLetterOrDigit(t[^1]) || t[^1] == '_' ? @"\b" : "";
            return $"{left}{e}{right}";
        });
        var pattern = string.Join("|", escaped);
        var options = System.Text.RegularExpressions.RegexOptions.None;
        if (!CaseSensitive)
            options |= System.Text.RegularExpressions.RegexOptions.IgnoreCase;

        System.Text.RegularExpressions.Regex? regex = null;
        try
        {
            regex = new System.Text.RegularExpressions.Regex(pattern, options);
        }
        catch
        {
            // Bad pattern — render plain
            _segments.Add(new Segment(Text, false));
            return;
        }

        int pos = 0;
        foreach (System.Text.RegularExpressions.Match m in regex.Matches(Text))
        {
            // Skip zero-length matches (e.g. a RegexMode pattern like "a*" or "\b")
            // so we never emit an empty highlight element. The surrounding non-match
            // text is still preserved by the next match's `m.Index > pos` check and
            // the trailing-text logic below. (#296)
            if (m.Length == 0)
                continue;
            if (m.Index > pos)
                _segments.Add(new Segment(Text[pos..m.Index], false));
            _segments.Add(new Segment(m.Value, true));
            pos = m.Index + m.Length;
        }

        if (pos < Text.Length)
            _segments.Add(new Segment(Text[pos..], false));
    }

    private record Segment(string Text, bool IsMatch);
}
